import json
import re

# Load businesses
with open(locals()['var_function-call-4563043634480549872'], 'r') as f:
    businesses = json.load(f)

us_states = {
    'AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD',
    'MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC',
    'SD','TN','TX','UT','VT','VA','WA','WV','WI','WY'
}
patterns = [re.compile(r"in [^,]+, ([A-Z]{2})"), re.compile(r"This [^,]+, ([A-Z]{2})")]

unparsed = []
parsed_count = 0
for b in businesses:
    desc = b.get('description', '')
    state = None
    for pat in patterns:
        m = pat.search(desc)
        if m and m.group(1) in us_states:
            state = m.group(1)
            break
    if not state:
        m = re.search(r", ([A-Z]{2})\b", desc)
        if m and m.group(1) in us_states:
            state = m.group(1)

    if state:
        parsed_count += 1
    else:
        unparsed.append(desc)

print("__RESULT__:")
print(json.dumps({
    "total": len(businesses),
    "parsed": parsed_count,
    "unparsed_count": len(unparsed),
    "sample_unparsed": unparsed[:5]
}))

